 import sailpoint.object.Filter;
import sailpoint.object.Link;
import sailpoint.object.QueryOptions;
import sailpoint.api.Terminator;

  private void pruneOrphanLinks(QueryOptions ops) {

  Terminator terminator = new Terminator(context);
  terminator.setTrace(true);


  if (ops != null && ops.getFilters() != null) {

    terminator.deleteObjects(Link.class, ops);

  }

}

Filter filter = Filter.isnull("identity");

QueryOptions ops = new QueryOptions();
ops.setCloneResults(true);
ops.addFilter(filter);
pruneOrphanLinks(ops);

return context.countObjects(Link.class, ops)+" Orphan Links are deleted" ;
